import { useState } from "react";
import { signInWithEmailAndPassword } from "firebase/auth";
import { ref, get } from "firebase/database";
import { auth, database } from "../firebase";
import { useNavigate } from "react-router-dom";

export default function DoctorLogin() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const navigate = useNavigate();

  const loginDoctor = async () => {
    try {
      const userCred = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCred.user.uid;

      const snapshot = await get(ref(database, `users/${uid}`));

      if (snapshot.exists() && snapshot.val().role === "doctor") {
        navigate("/doctor-dashboard");
      } else {
        alert("You are not a doctor");
      }
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="text-center text-primary">Doctor Login</h2>

      <div className="card p-4 shadow col-md-4 mx-auto mt-4">
        <input
          className="form-control mb-3"
          placeholder="Doctor Email"
          onChange={(e) => setEmail(e.target.value)}
        />
        <input
          type="password"
          className="form-control mb-3"
          placeholder="Password"
          onChange={(e) => setPassword(e.target.value)}
        />
        <button className="btn btn-primary w-100" onClick={loginDoctor}>
          Login
        </button>
      </div>
    </div>
  );
}
